#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

long long inv(long long a) {
    return powmod(a, MOD - 2);
}

int main() {
    int N;
    scanf("%d", &N);
    int u, v;
    long long strength = (long long)N * N;
    printf("%lld", strength);
    for (int i = 1; i < N; i++) {
        scanf("%d %d", &u, &v);
        strength = (strength * (N - i) + (long long)i * i) % MOD;
        strength = (strength * inv(N - i + 1)) % MOD;
        printf(" %lld", strength);
    }
    printf("\n");
    return 0;
}

